UPDATE signal_templates SET plan_override = '{"ai_filter_instruction": "The AI filter MUST check job-title relevance. Only keep leads where the scraped job title matches the user intended roles (marketing manager, marketing coordinator, CMO, VP Marketing, Head of Marketing, Director of Marketing). REJECT generic titles like Entry Level Marketing, Marketing Specialist, Influencer Marketing Coordinator, Paid Social Specialist, Content Creator, or any non-management marketing role. The filter should also verify the company is a marketing/advertising agency.", "person_enrichment": "Always include a person-enrichment stage to find decision makers. Use company_name as input. Search for CEO, Founder, Owner, Managing Director titles for small agencies.", "pipeline_hints": "Stage 1 should search job boards with queries combining agency type AND specific role titles. Use marketing agency marketing manager OR advertising agency CMO as search terms, NOT generic marketing jobs."}'::jsonb WHERE id = '564f66e5-c35f-46a7-a705-3c03fa8f4146';